// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper function to get weather emoji based on condition
function getWeatherEmoji(condition: string): string {
  const normalizedCondition = condition.toLowerCase().trim();
  if (normalizedCondition.includes('sunny') || normalizedCondition.includes('clear')) return '☀️';
  if (normalizedCondition.includes('cloudy') || normalizedCondition.includes('overcast')) return '☁️';
  if (normalizedCondition.includes('rainy') || normalizedCondition.includes('rain')) return '🌧️';
  if (normalizedCondition.includes('snow') || normalizedCondition.includes('snowy')) return '❄️';
  if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
  if (normalizedCondition.includes('windy') || normalizedCondition.includes('wind')) return '💨';
  if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) return '🌫️';
  return '🌤️'; // Default
}

export default function Component(props: Props) {
  // Get weather emoji for the current condition
  const weatherEmoji = getWeatherEmoji(props.condition);

  // Ensure forecast has valid data
  const validForecast = Array.isArray(props.forecast) ? props.forecast : [];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header: City and condition */}
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Heading level={1}>{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                {props.condition}
              </Text>
            </Stack>

            {/* Temperature Section with emoji */}
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Text
                size="4xl"
                weight="bold"
                color="var(--ggui-color-primary-600)"
                align="center"
              >
                {props.temperature}°{props.unit}
              </Text>
              <Text size="3xl" color="var(--ggui-color-primary-500)">{weatherEmoji}</Text>
            </Stack>

            {/* Divider */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />

            {/* Humidity and Wind Speed in a Row */}
            <Row gap="var(--ggui-spacing-6)" align="stretch" justify="center">
              <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Humidity
                </Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-500)" />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Wind Speed
                </Text>
                <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.windSpeed} km/h
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {validForecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">
              5-Day Forecast
            </Heading>
            <Row gap="var(--ggui-spacing-3)" align="stretch" wrap>
              {validForecast.map((dayForecast, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  border
                  style={{ flex: '1 1 150px', minWidth: '140px' }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    {/* Day Name */}
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                      {dayForecast.day || `Day ${index + 1}`}
                    </Text>

                    {/* Weather Icon/Emoji */}
                    {dayForecast.icon ? (
                      <Text size="2xl">{dayForecast.icon}</Text>
                    ) : (
                      <Icon name="cloud" size={32} color="var(--ggui-color-primary-500)" />
                    )}

                    {/* Temperature Range */}
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Text
                        variant="bodySmall"
                        weight="semibold"
                        color="var(--ggui-color-primary-600)"
                      >
                        {dayForecast.high !== undefined
                          ? `${dayForecast.high}°`
                          : '—'}
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant)"
                      >
                        {dayForecast.low !== undefined
                          ? `${dayForecast.low}°`
                          : '—'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}
